const uid = () => crypto.randomUUID()
const today = () => new Date().toISOString().slice(0, 10)
const money = v => Number(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })
const slugify = s => (s || 'meu-site').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '')

function authHeaders() {
  const token = localStorage.getItem(AUTH_TOKEN_KEY)
  return token ? { authorization: `Bearer ${token}` } : {}
}

function endSession() {
  const token = localStorage.getItem(AUTH_TOKEN_KEY)
  localStorage.removeItem(AUTH_TOKEN_KEY)
  if (token) fetch('/api/auth/session', { method: 'DELETE', headers: { authorization: `Bearer ${token}` } }).catch(() => {})
}

function useDatabase() {
  const [db, setDb] = useState(() => {
    try { return { ...emptyDb, ...JSON.parse(localStorage.getItem(STORAGE_KEY) || '{}') } } catch { return emptyDb }
  })
  useEffect(() => localStorage.setItem(STORAGE_KEY, JSON.stringify(db)), [db])
  const update = fn => setDb(current => typeof fn === 'function' ? fn(current) : { ...current, ...fn })
  return [db, update]
}

function Logo({ compact = false }) {
  return <div className="logo"><span className="logo-mark"><Sparkles size={19}/></span>{!compact && <span>Seu <strong>Funcionário</strong></span>}</div>
}

function Button({ children, icon: Icon, variant = 'primary', className = '', ...props }) {
  return <button className={`button ${variant} ${className}`} {...props}>{Icon && <Icon size={17}/>}<span>{children}</span></button>
}

function DynamicIcon({ icon: Icon, ...props }) { return Icon ? <Icon {...props}/> : null }

function Empty({ icon: Icon = Sparkles, title, text, action, onAction }) {
  return <div className="empty"><span className="empty-icon"><Icon size={23}/></span><h3>{title}</h3><p>{text}</p>{action && <Button icon={Plus} onClick={onAction}>{action}</Button>}</div>
}

function Modal({ title, children, onClose, wide = false }) {
  useEffect(() => { const h = e => e.key === 'Escape' && onClose(); addEventListener('keydown', h); return () => removeEventListener('keydown', h) }, [onClose])
  return <div className="modal-backdrop" role="presentation" onMouseDown={e => e.target === e.currentTarget && onClose()}><section className={`modal ${wide ? 'wide' : ''}`} role="dialog" aria-modal="true" aria-label={title}><div className="modal-head"><h2>{title}</h2><button className="icon-button" onClick={onClose} aria-label="Fechar"><X/></button></div>{children}</section></div>
}

function Field({ label, children, hint }) { return <label className="field"><span>{label}</span>{children}{hint && <small>{hint}</small>}</label> }

function Toast({ toast }) { return toast ? <div className="toast"><CheckCircle2 size={18}/>{toast}</div> : null }

function Login({ update }) {
  const [mode, setMode] = useState('login')
  const [form, setForm] = useState({ name: '', email: '', password: '' })
  const [error, setError] = useState('')
  const [busy, setBusy] = useState(false)
  const changeMode = next => { setMode(next); setError(''); setForm(current => ({ ...current, password: '' })) }
  const submit = async e => {
    e.preventDefault()
    setError('')
    const email = form.email.trim().toLowerCase()
    if (!/^\S+@\S+\.\S+$/.test(email)) return setError('Informe um e-mail válido.')
    if (form.password.length < 8) return setError('A senha precisa ter pelo menos 8 caracteres.')
    if (mode === 'register' && form.name.trim().length < 2) return setError('Informe seu nome.')
    setBusy(true)
    try {
      const response = await fetch(`/api/auth/${mode === 'login' ? 'login' : 'register'}`, {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ name: form.name.trim(), email, password: form.password })
      })
      const data = await response.json().catch(() => ({}))
      if (!response.ok) throw new Error(data.error || 'Não foi possível acessar sua conta.')
      localStorage.setItem(AUTH_TOKEN_KEY, data.token)
      update(d => ({ ...d, user: data.user }))
    } catch (reason) {
      setError(reason.message === 'Failed to fetch' ? 'Não foi possível conectar ao servidor. Tente novamente.' : reason.message)
    } finally { setBusy(false) }
  }
  return <main className="auth-shell"><div className="auth-art"><Logo/><div><span className="eyebrow light">SEU NEGÓCIO EM MOVIMENTO</span><h1>Tudo o que o seu negócio precisa, <em>mesmo sem uma equipe.</em></h1><p>Estratégia, marketing, vendas, organização e execução em um só lugar.</p></div><div className="auth-chips"><span><Target/>Planeje</span><span><WandSparkles/>Crie</span><span><CheckCircle2/>Execute</span></div></div><div className="auth-form"><div className="auth-card"><span className="mobile-logo"><Logo/></span><div className="auth-tabs" role="tablist" aria-label="Acesso"><button type="button" role="tab" aria-selected={mode === 'login'} className={mode === 'login' ? 'active' : ''} onClick={() => changeMode('login')}>Entrar</button><button type="button" role="tab" aria-selected={mode === 'register'} className={mode === 'register' ? 'active' : ''} onClick={() => changeMode('register')}>Criar conta</button></div><span className="eyebrow">{mode === 'login' ? 'BEM-VINDO DE VOLTA' : 'COMECE AGORA'}</span><h2>{mode === 'login' ? 'Entre no seu espaço' : 'Crie seu espaço de trabalho'}</h2><p>{mode === 'login' ? 'Use o e-mail e a senha cadastrados para continuar.' : 'Crie sua conta gratuita. Nenhum cartão é necessário.'}</p><form onSubmit={submit}>{mode === 'register' && <Field label="Seu nome"><input required autoComplete="name" value={form.name} onChange={e => setForm({...form, name:e.target.value})} placeholder="Como podemos chamar você?"/></Field>}<Field label="E-mail"><input required autoFocus={mode === 'login'} autoComplete="email" type="email" value={form.email} onChange={e => setForm({...form, email:e.target.value})} placeholder="voce@empresa.com"/></Field><Field label="Senha" hint={mode === 'register' ? 'Mínimo de 8 caracteres' : undefined}><input required minLength="8" autoComplete={mode === 'login' ? 'current-password' : 'new-password'} type="password" value={form.password} onChange={e => setForm({...form, password:e.target.value})} placeholder="••••••••"/></Field>{error && <div className="auth-error" role="alert"><CircleAlert/>{error}</div>}<Button className="full" type="submit" icon={mode === 'login' ? LogOut : ArrowUpRight} disabled={busy}>{busy ? 'Aguarde...' : mode === 'login' ? 'Entrar' : 'Criar minha conta'}</Button></form><p className="auth-switch">{mode === 'login' ? 'Ainda não tem uma conta?' : 'Já possui uma conta?'} <button type="button" onClick={() => changeMode(mode === 'login' ? 'register' : 'login')}>{mode === 'login' ? 'Criar conta gratuitamente' : 'Entrar agora'}</button></p><p className="privacy"><ShieldCheck/>Sua senha é protegida e a sessão pode ser usada em outros dispositivos. Os projetos deste protótipo continuam salvos no navegador atual.</p></div></div></main>
}

function Onboarding({ db, update }) {
  const [step, setStep] = useState(0)
  const [form, setForm] = useState({ stage:'Tenho apenas uma ideia', hasBusiness:'Sim', name:'', segment:'', need:'Organizar os próximos passos', areas:['Estratégia'] })
  const finish = skip => {
    let business = null
    if (!skip && form.name.trim()) business = { id: uid(), name: form.name.trim(), owner: db.user.name, segment: form.segment.trim(), stage: form.stage, goal: form.need, city:'', audience:'', offer:'', tone:'Profissional e acolhedor', createdAt: today(), main: true }
    update(d => ({ ...d, onboarding: true, businesses: business ? [business, ...d.businesses] : d.businesses, selectedBusinessId: business?.id || d.selectedBusinessId }))
  }
  const stages = ['Tenho apenas uma ideia','Estou estruturando o negócio','Estou começando a vender','Já tenho clientes','Quero organizar a operação','Quero aumentar as vendas','Quero profissionalizar a empresa','Quero expandir']
  const needs = ['Organizar os próximos passos','Conseguir clientes','Criar minha marca','Definir preços','Organizar a operação','Criar um site']
  return <main className="onboarding"><header><Logo/><button className="text-button" onClick={() => finish(true)}>Pular por enquanto</button></header><section className="onboard-card"><div className="steps"><span className={step>=0?'active':''}/><span className={step>=1?'active':''}/><span className={step>=2?'active':''}/></div>{step===0 && <><span className="eyebrow">PASSO 1 DE 3</span><h1>Onde seu negócio está hoje?</h1><p>Isso ajuda a mostrar as ferramentas mais úteis para você.</p><div className="option-grid">{stages.map(s => <button key={s} className={form.stage===s?'selected':''} onClick={() => setForm({...form,stage:s})}>{form.stage===s?<CheckCircle2/>:<Circle/>}{s}</button>)}</div></>}{step===1 && <><span className="eyebrow">PASSO 2 DE 3</span><h1>Conte um pouco sobre o negócio</h1><p>Você pode completar e editar tudo depois.</p><div className="form-grid"><Field label="Nome do negócio"><input autoFocus value={form.name} onChange={e=>setForm({...form,name:e.target.value})} placeholder="Ex.: Ateliê Aurora"/></Field><Field label="Segmento"><input value={form.segment} onChange={e=>setForm({...form,segment:e.target.value})} placeholder="Ex.: confeitaria, consultoria..."/></Field></div></>}{step===2 && <><span className="eyebrow">PASSO 3 DE 3</span><h1>O que mais precisa resolver agora?</h1><p>Seu painel será organizado a partir desta prioridade.</p><div className="option-grid compact">{needs.map(s => <button key={s} className={form.need===s?'selected':''} onClick={() => setForm({...form,need:s})}>{form.need===s?<CheckCircle2/>:<Circle/>}{s}</button>)}</div></>}<footer><Button variant="ghost" icon={ChevronLeft} disabled={step===0} onClick={()=>setStep(step-1)}>Voltar</Button>{step<2?<Button onClick={()=>setStep(step+1)}>Continuar <ChevronRight size={17}/></Button>:<Button icon={Sparkles} onClick={()=>finish(false)}>Preparar meu painel</Button>}</footer></section></main>
}

function BusinessForm({ value, onSave, onClose }) {
  const [f, setF] = useState(value || { name:'', owner:'', segment:'', stage:'Estou estruturando o negócio', city:'', audience:'', offer:'', goal:'', tone:'Profissional e acolhedor' })
  const save = e => { e.preventDefault(); if (!f.name.trim()) return; onSave({ ...f, id:f.id||uid(), name:f.name.trim(), createdAt:f.createdAt||today() }) }
  return <form className="modal-body" onSubmit={save}><div className="form-grid"><Field label="Nome do negócio"><input required value={f.name} onChange={e=>setF({...f,name:e.target.value})}/></Field><Field label="Responsável"><input value={f.owner} onChange={e=>setF({...f,owner:e.target.value})}/></Field><Field label="Segmento"><input value={f.segment} onChange={e=>setF({...f,segment:e.target.value})}/></Field><Field label="Estágio"><select value={f.stage} onChange={e=>setF({...f,stage:e.target.value})}><option>Tenho apenas uma ideia</option><option>Estou estruturando o negócio</option><option>Estou começando a vender</option><option>Já tenho clientes</option><option>Quero organizar a operação</option><option>Quero aumentar as vendas</option><option>Quero profissionalizar a empresa</option><option>Quero expandir</option></select></Field><Field label="Cidade ou região"><input value={f.city} onChange={e=>setF({...f,city:e.target.value})}/></Field><Field label="Público-alvo"><input value={f.audience} onChange={e=>setF({...f,audience:e.target.value})}/></Field><Field label="Produtos ou serviços"><textarea value={f.offer} onChange={e=>setF({...f,offer:e.target.value})}/></Field><Field label="Objetivo principal"><textarea value={f.goal} onChange={e=>setF({...f,goal:e.target.value})}/></Field><Field label="Tom de comunicação"><input value={f.tone} onChange={e=>setF({...f,tone:e.target.value})}/></Field></div><div className="modal-actions"><Button type="button" variant="ghost" onClick={onClose}>Cancelar</Button><Button type="submit" icon={Save}>Salvar negócio</Button></div></form>
}

function UniversalRequest({ db, update, business, setToast }) {
  const [text, setText] = useState(() => localStorage.getItem('sf-draft') || '')
  const [busy, setBusy] = useState(false)
  const [error, setError] = useState('')
  const endRef = useRef(null)
  const specialist = db.preferences.specialist
  const conversations=db.conversations||[]
  const active=conversations.find(x=>x.id===db.selectedConversationId)||null
  const messages=active?.messages||[]
  useEffect(()=>{ localStorage.setItem('sf-draft',text) },[text])
  useEffect(()=>{ endRef.current?.scrollIntoView({behavior:'smooth',block:'nearest'}) },[messages.length,busy])
  const newChat=()=>{update(d=>({...d,selectedConversationId:null}));setText('');setError('')}
  const saveMessage=message=>{const item={id:uid(),title:active?.title||'Conversa com IA',request:messages.find(x=>x.role==='user')?.content||'',result:message.content,specialist,provider:message.provider,model:message.model,businessId:business?.id||null,type:'Conversa salva',status:'Concluído',createdAt:new Date().toISOString()};update(d=>({...d,history:[item,...d.history]}));setToast('Resposta salva em Projetos e Histórico')}
  const submit = async () => {
    if (!text.trim() || busy) return
    const prompt=text.trim(),conversationId=active?.id||uid(),userMessage={id:uid(),role:'user',content:prompt,createdAt:new Date().toISOString()}
    const previousMessages=messages
    update(d=>{const list=d.conversations||[],exists=list.some(x=>x.id===conversationId),conversation=exists?null:{id:conversationId,title:prompt.slice(0,55),businessId:business?.id||null,specialist,createdAt:new Date().toISOString(),messages:[]};return{...d,selectedConversationId:conversationId,conversations:exists?list.map(x=>x.id===conversationId?{...x,messages:[...x.messages,userMessage],updatedAt:new Date().toISOString()}:x):[{...conversation,messages:[userMessage]},...list]}})
    setText('');localStorage.setItem('sf-draft','')
    setBusy(true); setError('')
    const controller = new AbortController(), timer = setTimeout(()=>controller.abort(),70000)
    try {
      const response = await fetch('/api/ai',{method:'POST',headers:{'content-type':'application/json',...authHeaders()},signal:controller.signal,body:JSON.stringify({prompt,specialist,messages:[...previousMessages,userMessage].slice(-10).map(x=>({role:x.role,content:x.content})),business:business?{name:business.name,segment:business.segment,stage:business.stage,audience:business.audience,offer:business.offer,goal:business.goal,tone:business.tone}:null})})
      const data = await response.json().catch(()=>({}))
      if(!response.ok) throw new Error(data.error||'Não foi possível obter uma resposta agora.')
      const assistantMessage={id:uid(),role:'assistant',content:data.content,provider:data.provider,model:data.model,degraded:!!data.degraded,toolIds:recommendedTools(prompt).map(x=>x.id),createdAt:new Date().toISOString()}
      update(d=>({...d,conversations:(d.conversations||[]).map(x=>x.id===conversationId?{...x,messages:[...x.messages,assistantMessage],updatedAt:new Date().toISOString()}:x)}));setToast(data.degraded?'Plano de contingência entregue':`Resposta criada com ${data.provider}`)
    } catch(err) {
      setText(prompt);setError(err.name==='AbortError'?'A resposta demorou demais. Seu texto foi restaurado para tentar novamente.':err.message)
    } finally { clearTimeout(timer); setBusy(false) }
  }
  const renderToolLink=id=>{const tool=toolCatalog.find(x=>x.id===id);if(!tool)return null;const ToolIcon=tool.icon;return <a href={tool.url} target="_blank" rel="noreferrer" key={id}><ToolIcon/><span><strong>{tool.name}</strong><small>{tool.badge}</small></span><ExternalLink/></a>}
  return <section className="ask-card chat-card"><div className="ask-top"><div><span className="spark-dot"><Sparkles/></span><div><h2>{active?.title||'O que você precisa resolver hoje?'}</h2><p>Converse, complemente e refine sem perder o contexto.</p></div></div><div className="chat-head-actions"><span className="business-context"><Building2/>{business?.name||'Nenhum negócio selecionado'}</span><Button variant="ghost" icon={Plus} onClick={newChat}>Nova conversa</Button></div></div>{conversations.length>0&&<div className="conversation-tabs">{conversations.slice(0,5).map(c=><button className={c.id===active?.id?'active':''} key={c.id} onClick={()=>update(d=>({...d,selectedConversationId:c.id}))}><MessageSquareText/>{c.title}</button>)}</div>}<div className={`chat-messages ${messages.length?'has-messages':''}`}>{messages.length===0?<div className="chat-welcome"><Bot/><h3>Seu agente está pronto</h3><p>Peça uma análise, material, plano ou orientação. Quando uma ferramenta externa for melhor, eu mostro o caminho certo.</p></div>:messages.map(message=><div className={`chat-message ${message.role}`} key={message.id}><span className="message-avatar">{message.role==='assistant'?<Sparkles/>:db.user.name[0]}</span><div className="message-content"><small>{message.role==='assistant'?(message.degraded?'Contingência local':`${message.provider} · ${message.model}`):db.user.name}</small><pre>{message.content}</pre>{message.toolIds?.length>0&&<div className="message-tools">{message.toolIds.map(renderToolLink)}</div>}{message.role==='assistant'&&<div className="message-actions"><button onClick={()=>{navigator.clipboard?.writeText(message.content);setToast('Resposta copiada')}}><Copy/>Copiar</button><button onClick={()=>saveMessage(message)}><Save/>Salvar em projetos</button></div>}</div></div>)}{busy&&<div className="chat-message assistant"><span className="message-avatar"><Sparkles/></span><div className="typing"><i/><i/><i/><span>Consultando a melhor IA disponível...</span></div></div>}<div ref={endRef}/></div><div className="chat-composer"><textarea aria-label="Mensagem para a IA" value={text} onChange={e=>setText(e.target.value.slice(0,8000))} onKeyDown={e=>{if(e.key==='Enter'&&!e.shiftKey&&!e.nativeEvent.isComposing){e.preventDefault();submit()}}} placeholder="Escreva sua mensagem..."/><div className="ask-actions"><div className="specialist-select"><span>Com</span><select aria-label="Especialista" value={specialist} onChange={e=>update(d=>({...d,preferences:{...d.preferences,specialist:e.target.value}}))}>{specialistData.map(s=><option key={s[0]}>{s[0]}</option>)}</select></div><span className="keyboard-hint">Enter envia · Shift + Enter quebra linha</span><span className="ai-live" title="Gemini Flash Lite, Gemini Flash, Gemma e Grok"><span/>Rede de IA</span><span className="counter">{text.length}/8000</span><Button icon={Send} disabled={!text.trim()||busy} onClick={submit}>{busy?'Pensando...':'Enviar'}</Button></div>{error&&<div className="ask-error"><CircleAlert/>{error}</div>}</div>{busy&&<div className="progress-line"><span/></div>}</section>
}

function Dashboard({ db, update, business, go, setToast }) {
  const activeTasks=db.tasks.filter(x=>x.status!=='Concluído'&&x.businessId===business?.id)
  const followups=db.leads.filter(x=>x.businessId===business?.id&&x.status!=='Ganho'&&x.status!=='Perdido')
  const recent=db.history.filter(x=>!business||x.businessId===business.id).slice(0,3)
  const quick=[['Validar uma ideia',Lightbulb,'comecar'],['Montar meus preços',Calculator,'financeiro'],['Encontrar clientes',Users,'vendas'],['Criar um site',Globe2,'sites'],['Organizar tarefas',ListTodo,'operacao'],['Criar uma proposta',FileText,'documentos']]
  return <><div className="welcome"><div><span className="eyebrow">CENTRAL DE TRABALHO</span><h1>Olá, {db.user.name.split(' ')[0]}. <span>Vamos fazer acontecer?</span></h1><p>{business ? <><strong>{business.name}</strong> está na fase “{business.stage}”.</> : 'Crie seu primeiro negócio para receber um painel personalizado.'}</p></div><div className="day-badge"><span>{new Date().toLocaleDateString('pt-BR',{weekday:'long'})}</span><strong>{new Date().getDate()}</strong><small>{new Date().toLocaleDateString('pt-BR',{month:'short'})}</small></div></div><UniversalRequest db={db} update={update} business={business} setToast={setToast}/><section className="section"><div className="section-head"><div><span className="eyebrow">ATALHOS</span><h2>Comece por aqui</h2></div></div><div className="quick-grid">{quick.map(([t,I,p],i)=><button key={t} onClick={()=>go(p)}><span className={`quick-icon q${i}`}><I/></span><span><strong>{t}</strong><small>Abrir ferramenta</small></span><ArrowUpRight/></button>)}</div></section><div className="dashboard-grid"><section className="panel"><div className="panel-head"><div><span className="eyebrow">EM ANDAMENTO</span><h2>Próximas ações</h2></div><button className="text-button" onClick={()=>go('operacao')}>Ver todas</button></div>{activeTasks.length?<div className="mini-list">{activeTasks.slice(0,4).map(t=><div key={t.id}><button aria-label="Concluir" onClick={()=>update(d=>({...d,tasks:d.tasks.map(x=>x.id===t.id?{...x,status:'Concluído'}:x)}))}><Circle/></button><span><strong>{t.title}</strong><small>{t.due||'Sem prazo'} · {t.priority}</small></span></div>)}</div>:<Empty icon={ListTodo} title="Nenhuma tarefa pendente" text="Transforme um plano em ações ou crie sua primeira tarefa."/>}</section><section className="panel"><div className="panel-head"><div><span className="eyebrow">RELACIONAMENTOS</span><h2>Leads para acompanhar</h2></div><button className="text-button" onClick={()=>go('vendas')}>Abrir CRM</button></div>{followups.length?<div className="mini-list">{followups.slice(0,4).map(l=><div key={l.id}><span className="avatar">{l.name[0]}</span><span><strong>{l.name}</strong><small>{l.status} · {l.next||'Sem follow-up'}</small></span></div>)}</div>:<Empty icon={Users} title="Seu CRM está livre" text="Adicione oportunidades e acompanhe cada conversa."/>}</section></div>{recent.length>0&&<section className="section"><div className="section-head"><div><span className="eyebrow">RECENTES</span><h2>Continue de onde parou</h2></div><button className="text-button" onClick={()=>go('historico')}>Ver histórico</button></div><div className="recent-grid">{recent.map(x=><article key={x.id}><span className="doc-icon"><Sparkles/></span><div><span className="tag">{x.specialist}</span><h3>{x.title}</h3><small>{new Date(x.createdAt).toLocaleString('pt-BR')}</small></div></article>)}</div></section>}</>
}

function Journeys({ db, update }) {
  const [open,setOpen]=useState(null)
  const toggle=(id,i)=>update(d=>{const arr=d.journeys[id]||[]; return {...d,journeys:{...d.journeys,[id]:arr.includes(i)?arr.filter(x=>x!==i):[...arr,i]}}})
  return <PageTitle eyebrow="JORNADAS GUIADAS" title="Um caminho claro para cada objetivo" text="Avance no seu ritmo. O progresso é salvo automaticamente."><div className="journey-grid">{Object.entries(journeyData).map(([id,j])=>{const done=db.journeys[id]||[];const pct=Math.round(done.length/j.steps.length*100);return <article className="journey-card" key={id}><span className="journey-icon"><DynamicIcon icon={j.icon}/></span><h2>{j.title}</h2><p>{j.steps.length} etapas práticas</p><div className="meter"><span style={{width:`${pct}%`}}/></div><div className="journey-meta"><span>{done.length} de {j.steps.length} concluídas</span><strong>{pct}%</strong></div><Button variant="secondary" onClick={()=>setOpen(id)}>{done.length?'Continuar jornada':'Começar jornada'}</Button></article>})}</div>{open&&<Modal title={journeyData[open].title} onClose={()=>setOpen(null)}><div className="journey-steps">{journeyData[open].steps.map((s,i)=>{const checked=(db.journeys[open]||[]).includes(i);return <button className={checked?'done':''} key={s} onClick={()=>toggle(open,i)}>{checked?<CheckCircle2/>:<Circle/>}<span><small>Etapa {i+1}</small><strong>{s}</strong></span></button>})}</div></Modal>}</PageTitle>
}

function PageTitle({ eyebrow, title, text, action, children }) { return <><div className="page-title"><div><span className="eyebrow">{eyebrow}</span><h1>{title}</h1><p>{text}</p></div>{action}</div>{children}</> }

function Specialists({ db, update, business, setToast }) {
  return <PageTitle eyebrow="ESPECIALISTAS DIGITAIS" title="A habilidade certa para cada desafio" text="Escolha um modo de trabalho. O contexto do negócio selecionado será considerado automaticamente."><UniversalRequest db={db} update={update} business={business} setToast={setToast}/><div className="specialist-grid">{specialistData.map(([n,I,d],i)=><button className={db.preferences.specialist===n?'active':''} key={n} onClick={()=>{update(x=>({...x,preferences:{...x.preferences,specialist:n}}));setToast(`${n} selecionado`)}}><span className={`quick-icon q${i%6}`}><I/></span><span><strong>{n}</strong><small>{d}</small></span>{db.preferences.specialist===n&&<CheckCircle2/>}</button>)}</div></PageTitle>
}

function Tasks({ db, update, business, setToast }) {
  const [modal,setModal]=useState(false); const [search,setSearch]=useState(''); const [view,setView]=useState('board')
  const [form,setForm]=useState({title:'',description:'',priority:'Média',status:'A fazer',due:'',area:'Operação'})
  const items=db.tasks.filter(t=>(!business||t.businessId===business.id)&&t.title.toLowerCase().includes(search.toLowerCase()))
  const add=e=>{e.preventDefault();if(!form.title.trim())return;update(d=>({...d,tasks:[{...form,id:uid(),businessId:business?.id||null,archived:false},...d.tasks]}));setModal(false);setForm({title:'',description:'',priority:'Média',status:'A fazer',due:'',area:'Operação'});setToast('Tarefa criada')}
  const statuses=['A fazer','Em andamento','Aguardando','Concluído']
  return <PageTitle eyebrow="OPERAÇÃO" title="Tarefas e projetos" text="Organize as próximas ações sem perder o contexto." action={<Button icon={Plus} onClick={()=>setModal(true)}>Nova tarefa</Button>}><div className="toolbar"><div className="search"><Search/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Pesquisar tarefas"/></div><div className="view-toggle"><button className={view==='board'?'active':''} onClick={()=>setView('board')}><GripVertical/>Quadro</button><button className={view==='list'?'active':''} onClick={()=>setView('list')}><ListTodo/>Lista</button></div></div>{items.length===0?<Empty icon={ListTodo} title="Nenhuma tarefa encontrada" text="Crie uma ação com prioridade e prazo para começar." action="Criar tarefa" onAction={()=>setModal(true)}/>:view==='board'?<div className="kanban">{statuses.map(s=><section key={s}><header><span>{s}</span><b>{items.filter(x=>x.status===s).length}</b></header>{items.filter(x=>x.status===s).map(t=><article key={t.id}><div><span className={`priority ${t.priority.toLowerCase()}`}>{t.priority}</span><button className="icon-button danger" onClick={()=>update(d=>({...d,tasks:d.tasks.filter(x=>x.id!==t.id)}))}><Trash2/></button></div><h3>{t.title}</h3><p>{t.description||'Sem descrição'}</p><footer><span><Clock3/>{t.due||'Sem prazo'}</span><select value={t.status} onChange={e=>update(d=>({...d,tasks:d.tasks.map(x=>x.id===t.id?{...x,status:e.target.value}:x)}))}>{statuses.map(x=><option key={x}>{x}</option>)}</select></footer></article>)}</section>)}</div>:<div className="data-list">{items.map(t=><article key={t.id}><button onClick={()=>update(d=>({...d,tasks:d.tasks.map(x=>x.id===t.id?{...x,status:x.status==='Concluído'?'A fazer':'Concluído'}:x)}))}>{t.status==='Concluído'?<CheckCircle2/>:<Circle/>}</button><span><strong>{t.title}</strong><small>{t.area} · {t.priority} · {t.due||'Sem prazo'}</small></span><select value={t.status} onChange={e=>update(d=>({...d,tasks:d.tasks.map(x=>x.id===t.id?{...x,status:e.target.value}:x)}))}>{statuses.map(x=><option key={x}>{x}</option>)}</select></article>)}</div>}{modal&&<Modal title="Criar tarefa" onClose={()=>setModal(false)}><form className="modal-body" onSubmit={add}><Field label="Título"><input autoFocus required value={form.title} onChange={e=>setForm({...form,title:e.target.value})}/></Field><Field label="Descrição"><textarea value={form.description} onChange={e=>setForm({...form,description:e.target.value})}/></Field><div className="form-grid"><Field label="Prioridade"><select value={form.priority} onChange={e=>setForm({...form,priority:e.target.value})}><option>Baixa</option><option>Média</option><option>Alta</option></select></Field><Field label="Status"><select value={form.status} onChange={e=>setForm({...form,status:e.target.value})}>{statuses.map(x=><option key={x}>{x}</option>)}</select></Field><Field label="Prazo"><input type="date" value={form.due} onChange={e=>setForm({...form,due:e.target.value})}/></Field><Field label="Área"><select value={form.area} onChange={e=>setForm({...form,area:e.target.value})}><option>Operação</option><option>Vendas</option><option>Marketing</option><option>Financeiro</option></select></Field></div><div className="modal-actions"><Button variant="ghost" onClick={()=>setModal(false)}>Cancelar</Button><Button type="submit" icon={Save}>Criar tarefa</Button></div></form></Modal>}</PageTitle>
}

function CRM({ db, update, business, setToast }) {
  const [modal,setModal]=useState(false),[search,setSearch]=useState(''),[filter,setFilter]=useState('Todos')
  const [form,setForm]=useState({name:'',company:'',contact:'',value:'',status:'Novo',next:'',notes:''})
  const stages=['Novo','Em conversa','Proposta enviada','Negociação','Ganho','Perdido']
  const leads=db.leads.filter(l=>(!business||l.businessId===business.id)&&(!search||`${l.name} ${l.company}`.toLowerCase().includes(search.toLowerCase()))&&(filter==='Todos'||l.status===filter))
  const add=e=>{e.preventDefault();if(!form.name.trim())return;update(d=>({...d,leads:[{...form,id:uid(),businessId:business?.id||null,createdAt:today()},...d.leads]}));setModal(false);setForm({name:'',company:'',contact:'',value:'',status:'Novo',next:'',notes:''});setToast('Lead adicionado ao CRM')}
  return <PageTitle eyebrow="VENDAS E CLIENTES" title="CRM simples, acompanhamento real" text="Centralize contatos, conversas, propostas e próximos passos." action={<Button icon={Plus} onClick={()=>setModal(true)}>Novo lead</Button>}><div className="metric-row"><Metric icon={Users} label="Leads" value={leads.length}/><Metric icon={TrendingUp} label="Em negociação" value={leads.filter(x=>['Proposta enviada','Negociação'].includes(x.status)).length}/><Metric icon={DollarSign} label="Valor informado" value={money(leads.filter(x=>x.status!=='Perdido').reduce((a,x)=>a+Number(x.value||0),0))}/></div><div className="toolbar"><div className="search"><Search/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Pesquisar nome ou empresa"/></div><select value={filter} onChange={e=>setFilter(e.target.value)}><option>Todos</option>{stages.map(x=><option key={x}>{x}</option>)}</select></div>{leads.length===0?<Empty icon={Users} title="Nenhuma oportunidade aqui" text="Adicione uma pessoa ou empresa e registre o próximo contato." action="Adicionar lead" onAction={()=>setModal(true)}/>:<div className="crm-table"><div className="table-head"><span>Contato</span><span>Etapa</span><span>Valor informado</span><span>Próximo contato</span><span/></div>{leads.map(l=><div key={l.id}><span className="contact-cell"><i>{l.name[0]}</i><span><strong>{l.name}</strong><small>{l.company||l.contact||'Sem empresa'}</small></span></span><select value={l.status} onChange={e=>update(d=>({...d,leads:d.leads.map(x=>x.id===l.id?{...x,status:e.target.value}:x)}))}>{stages.map(x=><option key={x}>{x}</option>)}</select><span>{l.value?money(l.value):'Não informado'}</span><span>{l.next||'Não agendado'}</span><button className="icon-button danger" onClick={()=>update(d=>({...d,leads:d.leads.filter(x=>x.id!==l.id)}))}><Trash2/></button></div>)}</div>}{modal&&<Modal title="Adicionar lead" onClose={()=>setModal(false)}><form className="modal-body" onSubmit={add}><div className="form-grid"><Field label="Nome"><input required autoFocus value={form.name} onChange={e=>setForm({...form,name:e.target.value})}/></Field><Field label="Empresa"><input value={form.company} onChange={e=>setForm({...form,company:e.target.value})}/></Field><Field label="E-mail ou telefone"><input value={form.contact} onChange={e=>setForm({...form,contact:e.target.value})}/></Field><Field label="Valor da oportunidade"><input type="number" min="0" step="0.01" value={form.value} onChange={e=>setForm({...form,value:e.target.value})}/></Field><Field label="Etapa"><select value={form.status} onChange={e=>setForm({...form,status:e.target.value})}>{stages.map(x=><option key={x}>{x}</option>)}</select></Field><Field label="Próximo contato"><input type="date" value={form.next} onChange={e=>setForm({...form,next:e.target.value})}/></Field></div><Field label="Observações"><textarea value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})}/></Field><div className="modal-actions"><Button variant="ghost" onClick={()=>setModal(false)}>Cancelar</Button><Button type="submit" icon={Save}>Salvar lead</Button></div></form></Modal>}</PageTitle>
}

function Metric({icon:Icon,label,value}){return <div className="metric"><span><Icon/></span><div><small>{label}</small><strong>{value}</strong></div></div>}

function Finance({db,update,business,setToast}){
  const [modal,setModal]=useState(false),[calc,setCalc]=useState({materials:'',hours:'',hourValue:'',fixed:'',tax:'',margin:''})
  const [form,setForm]=useState({type:'Receita',description:'',value:'',date:today(),category:'Geral'})
  const tx=db.transactions.filter(x=>!business||x.businessId===business.id), revenue=tx.filter(x=>x.type==='Receita').reduce((a,x)=>a+Number(x.value),0), expense=tx.filter(x=>x.type==='Despesa').reduce((a,x)=>a+Number(x.value),0)
  const base=Number(calc.materials||0)+Number(calc.hours||0)*Number(calc.hourValue||0)+Number(calc.fixed||0), tax=Number(calc.tax||0)/100, margin=Number(calc.margin||0)/100, suggested=(tax+margin)<1?base/(1-tax-margin):0
  const add=e=>{e.preventDefault();if(!form.description||!Number(form.value))return;update(d=>({...d,transactions:[{...form,id:uid(),businessId:business?.id||null},...d.transactions]}));setModal(false);setToast('Movimentação registrada')}
  return <PageTitle eyebrow="FINANCEIRO" title="Números claros para decisões melhores" text="Registre apenas valores reais. Projeções aparecem sempre identificadas como estimativas." action={<Button icon={Plus} onClick={()=>setModal(true)}>Registrar movimentação</Button>}><div className="metric-row"><Metric icon={ArrowUpRight} label="Receitas registradas" value={money(revenue)}/><Metric icon={ArrowUpRight} label="Despesas registradas" value={money(expense)}/><Metric icon={WalletCards} label="Saldo registrado" value={money(revenue-expense)}/></div><div className="finance-grid"><section className="panel calculator"><div className="panel-head"><div><span className="eyebrow">CALCULADORA</span><h2>Preço de venda</h2></div><Calculator/></div><p>Informe seus dados. Nenhum valor é preenchido ou presumido.</p><div className="form-grid"><Field label="Materiais (R$)"><input type="number" min="0" value={calc.materials} onChange={e=>setCalc({...calc,materials:e.target.value})}/></Field><Field label="Horas de trabalho"><input type="number" min="0" value={calc.hours} onChange={e=>setCalc({...calc,hours:e.target.value})}/></Field><Field label="Valor por hora (R$)"><input type="number" min="0" value={calc.hourValue} onChange={e=>setCalc({...calc,hourValue:e.target.value})}/></Field><Field label="Custos fixos rateados (R$)"><input type="number" min="0" value={calc.fixed} onChange={e=>setCalc({...calc,fixed:e.target.value})}/></Field><Field label="Impostos (%)"><input type="number" min="0" max="99" value={calc.tax} onChange={e=>setCalc({...calc,tax:e.target.value})}/></Field><Field label="Margem desejada (%)"><input type="number" min="0" max="99" value={calc.margin} onChange={e=>setCalc({...calc,margin:e.target.value})}/></Field></div><div className="calc-result"><span>Preço calculado</span><strong>{base?money(suggested):'Preencha os custos'}</strong><small>{base?(suggested?'Estimativa calculada a partir dos valores informados.':'Impostos + margem devem ser menores que 100%.'):'O resultado aparecerá aqui.'}</small></div></section><section className="panel"><div className="panel-head"><div><span className="eyebrow">MOVIMENTAÇÕES</span><h2>Registros recentes</h2></div></div>{tx.length?<div className="transactions">{tx.slice(0,8).map(x=><div key={x.id}><span className={x.type==='Receita'?'income':'expense'}>{x.type==='Receita'?'+':'−'}</span><span><strong>{x.description}</strong><small>{x.category} · {new Date(x.date+'T12:00').toLocaleDateString('pt-BR')}</small></span><b>{money(x.value)}</b><button className="icon-button danger" onClick={()=>update(d=>({...d,transactions:d.transactions.filter(t=>t.id!==x.id)}))}><Trash2/></button></div>)}</div>:<Empty icon={WalletCards} title="Nenhum valor registrado" text="Comece adicionando uma receita ou despesa real."/>}</section></div>{modal&&<Modal title="Registrar movimentação" onClose={()=>setModal(false)}><form className="modal-body" onSubmit={add}><div className="form-grid"><Field label="Tipo"><select value={form.type} onChange={e=>setForm({...form,type:e.target.value})}><option>Receita</option><option>Despesa</option></select></Field><Field label="Valor (R$)"><input required type="number" min="0.01" step="0.01" value={form.value} onChange={e=>setForm({...form,value:e.target.value})}/></Field><Field label="Descrição"><input required value={form.description} onChange={e=>setForm({...form,description:e.target.value})}/></Field><Field label="Categoria"><input value={form.category} onChange={e=>setForm({...form,category:e.target.value})}/></Field><Field label="Data"><input type="date" value={form.date} onChange={e=>setForm({...form,date:e.target.value})}/></Field></div><div className="modal-actions"><Button variant="ghost" onClick={()=>setModal(false)}>Cancelar</Button><Button type="submit" icon={Save}>Registrar</Button></div></form></Modal>}</PageTitle>
}

function Documents({db,update,business,setToast}){
  const [modal,setModal]=useState(false),[editing,setEditing]=useState(null),[search,setSearch]=useState('')
  const docs=db.documents.filter(x=>(!business||x.businessId===business.id)&&x.title.toLowerCase().includes(search.toLowerCase()))
  const [form,setForm]=useState({title:'',type:'Proposta comercial',content:''})
  const open=d=>{setForm(d||{title:'',type:'Proposta comercial',content:''});setEditing(d?.id||null);setModal(true)}
  const save=e=>{e.preventDefault();if(!form.title.trim())return;const item={...form,id:editing||uid(),businessId:business?.id||null,updatedAt:new Date().toISOString(),versions:editing?[...(db.documents.find(x=>x.id===editing)?.versions||[]),{content:form.content,at:new Date().toISOString()}]:[]};update(d=>({...d,documents:editing?d.documents.map(x=>x.id===editing?item:x):[item,...d.documents]}));setModal(false);setToast('Documento salvo')}
  const download=d=>{const blob=new Blob([d.content],{type:'text/plain;charset=utf-8'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`${slugify(d.title)}.txt`;a.click();URL.revokeObjectURL(a.href)}
  return <PageTitle eyebrow="DOCUMENTOS" title="Crie, edite e leve seu trabalho com você" text="Propostas, planos, relatórios e materiais ficam organizados por negócio." action={<Button icon={Plus} onClick={()=>open(null)}>Novo documento</Button>}><div className="toolbar"><div className="search"><Search/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Pesquisar documentos"/></div></div>{docs.length===0?<Empty icon={FileText} title="Nenhum documento criado" text="Crie um documento editável e exporte em texto quando quiser." action="Criar documento" onAction={()=>open(null)}/>:<div className="document-grid">{docs.map(d=><article key={d.id}><span className="doc-icon"><FileText/></span><span className="tag">{d.type}</span><h3>{d.title}</h3><p>{d.content.slice(0,100)||'Documento vazio'}</p><small>Atualizado {new Date(d.updatedAt).toLocaleString('pt-BR')}</small><footer><button onClick={()=>open(d)}><Edit3/>Editar</button><button onClick={()=>download(d)}><Download/>Baixar</button><button className="danger" onClick={()=>update(x=>({...x,documents:x.documents.filter(y=>y.id!==d.id)}))}><Trash2/></button></footer></article>)}</div>}{modal&&<Modal title={editing?'Editar documento':'Novo documento'} onClose={()=>setModal(false)} wide><form className="modal-body" onSubmit={save}><div className="form-grid"><Field label="Título"><input required autoFocus value={form.title} onChange={e=>setForm({...form,title:e.target.value})}/></Field><Field label="Tipo"><select value={form.type} onChange={e=>setForm({...form,type:e.target.value})}>{['Proposta comercial','Plano de negócio','Plano de marketing','Orçamento','Relatório','Checklist','Procedimento','Apresentação','Briefing','Plano de ação'].map(x=><option key={x}>{x}</option>)}</select></Field></div><Field label="Conteúdo"><textarea className="editor" value={form.content} onChange={e=>setForm({...form,content:e.target.value})} placeholder="Escreva ou cole o conteúdo aqui..."/></Field><div className="modal-actions"><Button variant="ghost" onClick={()=>setModal(false)}>Cancelar</Button><Button type="submit" icon={Save}>Salvar documento</Button></div></form></Modal>}</PageTitle>
}

function makeSite(form){
  const title=form.name||'Meu negócio', desc=form.description||'Soluções pensadas para você.', c=form.color||'#6d38e0', contact=form.contact||'#contato'
  return `<!doctype html><html lang="pt-BR"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${escapeHtml(title)}</title><meta name="description" content="${escapeHtml(desc.slice(0,150))}"><style>*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;color:#17152b;background:#fafaff}header{display:flex;justify-content:space-between;align-items:center;padding:24px 7%;background:#fff}header b{font-size:1.2rem}a{color:inherit}.cta{display:inline-block;background:${c};color:white;padding:14px 22px;border-radius:12px;text-decoration:none;font-weight:700}.hero{padding:100px 7%;background:linear-gradient(135deg,#f4f0ff,#fff0f7);min-height:66vh;display:grid;align-content:center}.hero div{max-width:760px}.hero span{color:${c};font-weight:800;text-transform:uppercase;letter-spacing:.12em}.hero h1{font-size:clamp(2.5rem,7vw,5.5rem);line-height:1;margin:.25em 0}.hero p{font-size:1.2rem;line-height:1.7;max-width:640px}.section{padding:75px 7%}.section h2{font-size:2.2rem}.cards{display:grid;grid-template-columns:repeat(3,1fr);gap:20px}.card{background:#fff;padding:26px;border:1px solid #e8e5f2;border-radius:18px}.contact{background:#17152b;color:#fff;text-align:center}footer{padding:28px 7%;text-align:center;color:#666}@media(max-width:700px){header{padding:18px 5%}.hero,.section{padding:64px 6%}.cards{grid-template-columns:1fr}}</style></head><body><header><b>${escapeHtml(title)}</b><a class="cta" href="${escapeHtml(contact)}">Entrar em contato</a></header><main><section class="hero"><div><span>${escapeHtml(form.segment||'Bem-vindo')}</span><h1>${escapeHtml(form.headline||title)}</h1><p>${escapeHtml(desc)}</p><a class="cta" href="${escapeHtml(contact)}">${escapeHtml(form.cta||'Quero saber mais')}</a></div></section><section class="section"><h2>Como podemos ajudar</h2><div class="cards">${(form.services||'Atendimento personalizado\nSolução sob medida\nAcompanhamento próximo').split('\n').filter(Boolean).slice(0,6).map(s=>`<div class="card"><h3>${escapeHtml(s)}</h3><p>Converse conosco para entender como esta solução pode atender ao que você precisa.</p></div>`).join('')}</div></section><section class="section contact" id="contato"><h2>Vamos conversar?</h2><p>Conte o que você precisa e receba os próximos passos.</p><a class="cta" href="${escapeHtml(contact)}">${escapeHtml(form.cta||'Falar agora')}</a></section></main><footer>© ${new Date().getFullYear()} ${escapeHtml(title)}</footer></body></html>`
}
const escapeHtml=s=>String(s||'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))

export function websiteMilestones(site){
  const brief=site?.brief||{}
  const serviceCount=(brief.services||'').split('\n').filter(x=>x.trim()).length
  const reviewed=site?.reviewedDevices||[]
  return [
    {id:'created',title:'Projeto criado',text:'Gerar e salvar uma página funcional.',done:!!site},
    {id:'brief',title:'Briefing consistente',text:'Informar nome, segmento e objetivo da página.',done:!!(site&&brief.name&&brief.segment&&brief.description)},
    {id:'content',title:'Conteúdo estruturado',text:'Definir título principal e pelo menos dois serviços.',done:!!(site&&brief.headline&&serviceCount>=2)},
    {id:'identity',title:'Identidade personalizada',text:'Personalizar cor, chamada ou conteúdo do código.',done:!!(site&&(site.codeEdited||(brief.color&&brief.color!=='#6d38e0')||(brief.cta&&brief.cta!=='Falar com a gente')))},
    {id:'responsive',title:'Revisão responsiva',text:'Conferir o resultado em desktop, tablet e celular.',done:['desktop','tablet','mobile'].every(x=>reviewed.includes(x))},
    {id:'published',title:'Publicação concluída',text:'Publicar a versão final do projeto.',done:!!site?.published}
  ]
}

function Sites({db,update,business,setToast}){
  const [modal,setModal]=useState(false),[preview,setPreview]=useState(null),[device,setDevice]=useState('desktop'),[editCode,setEditCode]=useState(false)
  const [form,setForm]=useState({name:business?.name||'',segment:business?.segment||'',description:'',headline:'',services:business?.offer||'',cta:'Falar com a gente',contact:'#contato',color:'#6d38e0'})
  const sites=db.sites.filter(x=>!business||x.businessId===business.id)
  const generate=e=>{e.preventDefault();if(!form.description.trim())return;let slug=slugify(form.name);let n=2;while(db.sites.some(x=>x.slug===slug))slug=`${slugify(form.name)}-${n++}`;const site={id:uid(),name:form.name||'Novo site',slug,html:makeSite(form),brief:{...form},published:false,businessId:business?.id||null,createdAt:new Date().toISOString(),updatedAt:new Date().toISOString(),leads:[],reviewedDevices:[],codeEdited:false};update(d=>({...d,sites:[site,...d.sites]}));setModal(false);setPreview(site.id);setToast('Site criado e salvo')}
  const current=db.sites.find(x=>x.id===preview)
  const updateSite=(id,patch)=>update(d=>({...d,sites:d.sites.map(x=>x.id===id?{...x,...patch,updatedAt:new Date().toISOString()}:x)}))
  const download=s=>{const blob=new Blob([s.html],{type:'text/html'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`${s.slug}.html`;a.click();URL.revokeObjectURL(a.href)}
  if(current){const progress=websiteMilestones(current);const completed=progress.filter(x=>x.done).length;return <PageTitle eyebrow="EDITOR DE SITE" title={current.name} text={current.published?`Publicado em /s/${current.slug}`:'Rascunho privado'} action={<Button variant="ghost" icon={ChevronLeft} onClick={()=>setPreview(null)}>Meus sites</Button>}><div className="cert-progress-mini"><span className="cert-mini-icon"><Award/></span><div><strong>Trilha: Criação de Websites No-Code</strong><small>{completed} de {progress.length} marcos concluídos para liberar o certificado</small></div><div className="meter"><span style={{width:`${completed/progress.length*100}%`}}/></div></div><div className="site-toolbar"><div className="view-toggle"><button className={device==='desktop'?'active':''} onClick={()=>{setDevice('desktop');updateSite(current.id,{reviewedDevices:[...new Set([...(current.reviewedDevices||[]),'desktop'])]})}}><Monitor/>Desktop</button><button className={device==='tablet'?'active':''} onClick={()=>{setDevice('tablet');updateSite(current.id,{reviewedDevices:[...new Set([...(current.reviewedDevices||[]),'tablet'])]})}}><Tablet/>Tablet</button><button className={device==='mobile'?'active':''} onClick={()=>{setDevice('mobile');updateSite(current.id,{reviewedDevices:[...new Set([...(current.reviewedDevices||[]),'mobile'])]})}}><Smartphone/>Celular</button></div><div><Button variant="ghost" icon={Edit3} onClick={()=>setEditCode(!editCode)}>{editCode?'Ver preview':'Editar HTML'}</Button><Button icon={current.published?Eye:Globe2} onClick={()=>{updateSite(current.id,{published:!current.published});setToast(current.published?'Site despublicado':'Site publicado')}}>{current.published?'Despublicar':'Publicar'}</Button></div></div>{editCode?<div className="code-editor"><div><span>HTML completo</span><small>Scripts inseridos são bloqueados no preview.</small></div><textarea value={current.html} onChange={e=>updateSite(current.id,{html:e.target.value,codeEdited:true})}/></div>:<div className={`site-preview ${device}`}><iframe title={`Preview de ${current.name}`} sandbox="allow-forms allow-popups" srcDoc={current.html}/></div>}</PageTitle>}
  return <PageTitle eyebrow="SITES E MATERIAIS" title="Crie uma presença digital de verdade" text="Gere páginas completas, edite o código, visualize em diferentes telas e exporte." action={<Button icon={Plus} onClick={()=>setModal(true)}>Criar site</Button>}>{sites.length===0?<Empty icon={Globe2} title="Nenhum site criado" text="Descreva seu negócio e gere uma página responsiva pronta para editar." action="Criar meu primeiro site" onAction={()=>setModal(true)}/>:<div className="sites-grid">{sites.map(s=><article key={s.id}><div className="site-thumb"><iframe title="Miniatura" sandbox="" srcDoc={s.html}/><span className={s.published?'live':''}>{s.published?'Publicado':'Rascunho'}</span></div><div><h3>{s.name}</h3><p>/s/{s.slug}</p><small>Atualizado {new Date(s.updatedAt).toLocaleString('pt-BR')}</small><footer><button onClick={()=>setPreview(s.id)}><Edit3/>Editar</button><button onClick={()=>download(s)}><Download/>Baixar</button><button onClick={()=>{navigator.clipboard?.writeText(s.html);setToast('Código copiado')}}><Copy/>Código</button><button className="danger" onClick={()=>update(d=>({...d,sites:d.sites.filter(x=>x.id!==s.id)}))}><Trash2/></button></footer></div></article>)}</div>}{modal&&<Modal title="Criar um site" wide onClose={()=>setModal(false)}><form className="modal-body" onSubmit={generate}><Field label="Descreva o site que precisa"><textarea required autoFocus value={form.description} onChange={e=>setForm({...form,description:e.target.value})} placeholder="Ex.: Uma landing page para apresentar meus serviços de organização residencial..."/></Field><div className="form-grid"><Field label="Nome do negócio"><input value={form.name} onChange={e=>setForm({...form,name:e.target.value})}/></Field><Field label="Segmento"><input value={form.segment} onChange={e=>setForm({...form,segment:e.target.value})}/></Field><Field label="Título principal"><input value={form.headline} onChange={e=>setForm({...form,headline:e.target.value})} placeholder="Se vazio, usa o nome do negócio"/></Field><Field label="Chamada do botão"><input value={form.cta} onChange={e=>setForm({...form,cta:e.target.value})}/></Field><Field label="Contato ou link"><input value={form.contact} onChange={e=>setForm({...form,contact:e.target.value})} placeholder="https://wa.me/..."/></Field><Field label="Cor principal"><input type="color" value={form.color} onChange={e=>setForm({...form,color:e.target.value})}/></Field></div><Field label="Serviços (um por linha)"><textarea value={form.services} onChange={e=>setForm({...form,services:e.target.value})}/></Field><div className="notice"><ShieldCheck/><span>O gerador não adiciona depoimentos, clientes, números ou imagens inventadas.</span></div><div className="modal-actions"><Button variant="ghost" onClick={()=>setModal(false)}>Cancelar</Button><Button type="submit" icon={WandSparkles}>Gerar site</Button></div></form></Modal>}</PageTitle>
}

function EmailComposer({onClose,setToast}){
  const [form,setForm]=useState({to:'',subject:'',body:''})
  const params=()=>`to=${encodeURIComponent(form.to)}&su=${encodeURIComponent(form.subject)}&body=${encodeURIComponent(form.body)}`
  const openGmail=()=>{window.open(`https://mail.google.com/mail/?view=cm&fs=1&${params()}`,'_blank','noopener');setToast('Rascunho aberto no Gmail para sua confirmação')}
  const openOutlook=()=>{window.open(`https://outlook.office.com/mail/deeplink/compose?to=${encodeURIComponent(form.to)}&subject=${encodeURIComponent(form.subject)}&body=${encodeURIComponent(form.body)}`,'_blank','noopener');setToast('Rascunho aberto no Outlook para sua confirmação')}
  const openClient=()=>{location.href=`mailto:${encodeURIComponent(form.to)}?subject=${encodeURIComponent(form.subject)}&body=${encodeURIComponent(form.body)}`}
  return <Modal title="Escrever e-mail" wide onClose={onClose}><div className="modal-body"><div className="notice"><ShieldCheck/><span>O Seu Funcionário prepara a mensagem. O envio final acontece na sua conta de e-mail, para você revisar destinatário e conteúdo.</span></div><div className="form-grid"><Field label="Para"><input type="email" value={form.to} onChange={e=>setForm({...form,to:e.target.value})} placeholder="cliente@empresa.com"/></Field><Field label="Assunto"><input value={form.subject} onChange={e=>setForm({...form,subject:e.target.value})} placeholder="Assunto do e-mail"/></Field></div><Field label="Mensagem"><textarea className="email-body" value={form.body} onChange={e=>setForm({...form,body:e.target.value})} placeholder="Escreva ou cole sua mensagem..."/></Field><div className="email-actions"><Button icon={Mail} onClick={openGmail}>Abrir no Gmail</Button><Button variant="secondary" icon={Mail} onClick={openOutlook}>Abrir no Outlook</Button><Button variant="ghost" icon={ExternalLink} onClick={openClient}>Usar aplicativo padrão</Button></div></div></Modal>
}

