function CreativeStudio({db,update,business,setToast}){
  const [type,setType]=useState('logo'),[prompt,setPrompt]=useState(''),[busy,setBusy]=useState(false),[error,setError]=useState(''),[ack,setAck]=useState(false),[progress,setProgress]=useState(0)
  const items=(db.media||[]).filter(x=>!business||x.businessId===business.id)
  const generate=async()=>{if(prompt.trim().length<5||busy)return;setBusy(true);setError('');setProgress(5);try{const response=await fetch('/api/media',{method:'POST',headers:{'content-type':'application/json',...authHeaders()},body:JSON.stringify({type,prompt:prompt.trim(),confirmPaid:ack,quality:type==='video'?'advanced':undefined})});const data=await response.json();if(!response.ok)throw new Error(data.error||'Não foi possível gerar o material.');const item={id:uid(),type,prompt:prompt.trim(),status:data.status,url:data.url||null,requestId:data.requestId||null,model:data.model,provider:data.provider||null,freeTier:!!data.freeTier,businessId:business?.id||null,createdAt:new Date().toISOString()};update(d=>({...d,media:[item,...(d.media||[])]}));if(type==='video'&&data.requestId){let finished=false;for(let i=0;i<180;i++){await new Promise(resolve=>setTimeout(resolve,5000));const check=await fetch(`/api/media?request_id=${encodeURIComponent(data.requestId)}`,{headers:authHeaders()}),status=await check.json();if(!check.ok)throw new Error(status.error||'Não foi possível consultar a geração.');setProgress(status.progress||Math.min(96,8+Math.round(i*.5)));if(status.status==='done'&&status.url){update(d=>({...d,media:(d.media||[]).map(x=>x.id===item.id?{...x,status:'done',url:status.url,duration:status.duration}:x)}));setToast('Vídeo generativo concluído');finished=true;break}if(status.status==='failed'||status.status==='expired')throw new Error(status.error||'A geração do vídeo não foi concluída.')}if(!finished)throw new Error('A geração continua no servidor. Ela permanecerá na fila; tente consultar novamente em alguns minutos.')}else setToast(data.freeTier?(type==='logo'?'Logo criado na infraestrutura gratuita':'Imagem criada na infraestrutura gratuita'):(type==='logo'?'Conceito de logo criado':'Imagem criada'));setPrompt('')}catch(err){setError(err.message)}finally{setBusy(false);setProgress(0)}}
  const labels={logo:{title:'Criador de logos',text:'Descreva nome, segmento, personalidade, cores e símbolos que devem ser evitados.',placeholder:'Ex.: Logo para uma confeitaria artesanal chamada Doce Norte, elegante, acolhedora, terracota e creme...'},image:{title:'Gerador de imagens',text:'Crie imagens para campanhas, sites, produtos e redes sociais.',placeholder:'Ex.: Fotografia editorial de uma mesa com bolos artesanais, luz natural suave...'},video:{title:'Gerador de vídeos',text:'Gere um vídeo curto de seis segundos a partir de uma descrição.',placeholder:'Ex.: Câmera se aproxima lentamente de uma vitrine de confeitaria ao amanhecer...'}}[type]
  const changeType=next=>{setType(next);setAck(false);setError('')}
  return <PageTitle eyebrow="ESTÚDIO CRIATIVO" title="Crie materiais visuais com IA" text="Vídeos são gerados pelo motor aberto do Seu Funcionário, hospedado na nuvem e sem franquia por usuário."><div className="studio-tabs"><button className={type==='logo'?'active':''} onClick={()=>changeType('logo')}><Palette/>Logos</button><button className={type==='image'?'active':''} onClick={()=>changeType('image')}><ImageIcon/>Imagens</button><button className={type==='video'?'active':''} onClick={()=>changeType('video')}><Video/>Vídeos</button></div><section className="studio-creator"><div className="studio-copy"><span className="spark-dot"><WandSparkles/></span><h2>{labels.title}</h2><p>{labels.text}</p><div className="studio-points"><span><CheckCircle2/>Prompt aprimorado automaticamente</span><span><CheckCircle2/>{type==='video'?'Wan 2.2 · 720p · sem créditos por vídeo':'Cloudflare FLUX primeiro'}</span><span><ShieldCheck/>Sem marcas ou depoimentos inventados</span></div></div><div className="studio-form"><Field label="Descreva o que deseja criar"><textarea value={prompt} onChange={e=>setPrompt(e.target.value.slice(0,3000))} placeholder={labels.placeholder}/></Field>{type!=='video'&&<label className="cost-check"><input type="checkbox" checked={ack} onChange={e=>setAck(e.target.checked)}/><span>Se a opção principal falhar, permitir o provedor alternativo configurado.</span></label>}{type==='video'&&<><div className="notice"><Video/><span>IA generativa própria em servidor GPU. Não usa seu computador e não existe limite artificial de gerações; pedidos simultâneos entram em fila.</span></div><a className="button secondary" href="https://huggingface.co/spaces/Lightricks/LTX-2-3" target="_blank" rel="noreferrer"><ExternalLink size={17}/><span>Usar LTX‑2.3 grátis no Hugging Face</span></a><small>Modo gratuito oficial: sujeito à fila e ao limite diário do ZeroGPU.</small></>}{error&&<div className="ask-error"><CircleAlert/>{error}</div>}<Button icon={busy?RefreshCw:WandSparkles} disabled={busy||prompt.trim().length<5} onClick={generate}>{busy?(type==='video'?`Gerando vídeo${progress?` · ${progress}%`:''}`:'Criando...'):'Gerar agora'}</Button></div></section>{items.length>0&&<section className="section"><div className="section-head"><div><span className="eyebrow">CRIAÇÕES</span><h2>Galeria do negócio</h2></div></div><div className="media-grid">{items.map(item=><article key={item.id}>{item.status==='done'&&item.url?(item.type==='video'?<video controls src={item.url}/>:<img src={item.url} alt={item.prompt}/>):<div className="media-pending"><RefreshCw/><span>Processando</span></div>}<div><span className="tag">{item.type==='logo'?'Logo':item.type==='image'?'Imagem':'Vídeo'}</span><p>{item.prompt}</p>{item.provider&&<small>{item.provider}{item.freeTier?' · infraestrutura gratuita':''}</small>}{item.url&&<a href={item.url} target="_blank" rel="noreferrer" download>Abrir e baixar <Download/></a>}</div></article>)}</div></section>}</PageTitle>
}

function HistoryPage({db,update,business,setToast}){
  const [open,setOpen]=useState(null),[search,setSearch]=useState('')
  const items=db.history.filter(x=>(!business||x.businessId===business.id)&&x.title.toLowerCase().includes(search.toLowerCase()))
  const transform=(x,type)=>{if(type==='task')update(d=>({...d,tasks:[{id:uid(),title:x.title,description:x.result.slice(0,240),priority:'Média',status:'A fazer',due:'',area:'Estratégia',businessId:x.businessId},...d.tasks]}));else update(d=>({...d,documents:[{id:uid(),title:x.title,type:'Plano de ação',content:x.result,businessId:x.businessId,updatedAt:new Date().toISOString(),versions:[]},...d.documents]}));setToast(type==='task'?'Tarefa criada':'Documento criado')}
  return <PageTitle eyebrow="PROJETOS E HISTÓRICO" title="Tudo o que você escolheu guardar, pronto para continuar" text="As conversas ficam no chat; somente respostas que você salvar entram aqui."><div className="toolbar"><div className="search"><Search/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Pesquisar no histórico"/></div></div>{items.length===0?<Empty icon={History} title="Seu histórico está vazio" text="No chat, use “Salvar em projetos” apenas nas respostas que quiser manter aqui."/>:<div className="history-list">{items.map(x=><article key={x.id} onClick={()=>setOpen(x.id)}><span className="doc-icon"><Sparkles/></span><span><span className="tag">{x.specialist}</span><h3>{x.title}</h3><small>{new Date(x.createdAt).toLocaleString('pt-BR')} · {x.type}{x.provider?` · ${x.provider}`:''}</small></span><ChevronRight/></article>)}</div>}{open&&(()=>{const x=db.history.find(i=>i.id===open);return <Modal wide title={x.title} onClose={()=>setOpen(null)}><div className="result"><div className="result-meta"><span><Building2/>{db.businesses.find(b=>b.id===x.businessId)?.name||'Sem negócio'}</span><span><Sparkles/>{x.specialist}</span>{x.provider&&<span><BadgeCheck/>{x.provider} · {x.model}</span>}</div><pre>{x.result}</pre><div className="modal-actions spread"><Button variant="ghost" icon={Copy} onClick={()=>{navigator.clipboard?.writeText(x.result);setToast('Resultado copiado')}}>Copiar</Button><div><Button variant="secondary" icon={ListTodo} onClick={()=>transform(x,'task')}>Virar tarefa</Button><Button icon={FileText} onClick={()=>transform(x,'doc')}>Virar documento</Button></div></div></div></Modal>})()}</PageTitle>
}

function certificateDocument(cert){
  return `<!doctype html><html lang="pt-BR"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>${escapeHtml(cert.title)}</title><style>@page{size:A4 landscape;margin:0}*{box-sizing:border-box}body{margin:0;background:#eee;font-family:Arial,sans-serif;color:#18142b}.sheet{width:297mm;height:210mm;margin:auto;background:#fff;padding:13mm;position:relative;overflow:hidden}.frame{height:100%;border:2px solid #2b2051;padding:8mm;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;position:relative}.frame:before,.frame:after{content:'';position:absolute;width:100mm;height:100mm;border-radius:50%;filter:blur(2px);opacity:.12}.frame:before{background:#6d38e0;left:-50mm;top:-55mm}.frame:after{background:#ed3e91;right:-48mm;bottom:-58mm}.mark{width:18mm;height:18mm;border-radius:5mm;background:linear-gradient(135deg,#6d38e0,#ed3e91);color:white;display:grid;place-items:center;font-size:9mm;font-weight:bold;margin-bottom:5mm}.issuer{font-size:4mm;letter-spacing:.16em;text-transform:uppercase;font-weight:bold;color:#6d38e0}.sub{font-size:3.1mm;color:#665f75;margin-top:2mm}.rule{width:35mm;height:.6mm;background:linear-gradient(90deg,#6d38e0,#ed3e91);margin:6mm}.label{font-size:3.5mm;color:#665f75}.name{font-family:Georgia,serif;font-size:12mm;margin:4mm 0;color:#211846}.text{font-size:4mm;line-height:1.6;max-width:205mm;color:#413a50}.title{font-size:7mm;font-weight:bold;color:#6d38e0;margin:3mm 0}.footer{display:flex;gap:24mm;margin-top:10mm}.footer div{min-width:55mm;border-top:.4mm solid #aaa;padding-top:2mm;font-size:3.2mm}.code{position:absolute;bottom:6mm;font-size:2.8mm;color:#777}.note{position:absolute;left:10mm;bottom:5mm;font-size:2.5mm;color:#888;max-width:65mm;text-align:left}@media print{body{background:#fff}.sheet{margin:0}}</style></head><body><main class="sheet"><section class="frame"><div class="mark">P</div><div class="issuer">Academia Praxis</div><div class="sub">Competências Aplicadas para Negócios</div><div class="rule"></div><div class="label">CERTIFICADO DE COMPETÊNCIA PRÁTICA</div><h1 class="name">${escapeHtml(cert.name)}</h1><div class="text">concluiu os marcos verificáveis da trilha e demonstrou competência aplicada em</div><h2 class="title">${escapeHtml(cert.title)}</h2><div class="text">por estruturar briefing e conteúdo, personalizar a experiência, validar a responsividade e concluir a publicação de um projeto funcional.</div><div class="footer"><div><strong>${new Date(cert.issuedAt).toLocaleDateString('pt-BR')}</strong><br>Data de emissão</div><div><strong>Academia Praxis</strong><br>Unidade formativa</div></div><div class="note">Programa formativo integrado ao aplicativo Seu Funcionário. Certificado de realização prática; não equivale a diploma acadêmico ou habilitação profissional regulamentada.</div><div class="code">Credencial ${escapeHtml(cert.code)} · Projeto: ${escapeHtml(cert.projectName)}</div></section></main></body></html>`
}

function CertificateView({cert,onClose}){
  const download=()=>{const blob=new Blob([certificateDocument(cert)],{type:'text/html;charset=utf-8'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`certificado-${slugify(cert.name)}.html`;a.click();URL.revokeObjectURL(a.href)}
  const print=()=>{const w=window.open('','_blank');if(!w)return;w.document.write(certificateDocument(cert));w.document.close();setTimeout(()=>w.print(),350)}
  return <Modal wide title="Sua credencial" onClose={onClose}><div className="certificate"><div className="certificate-inner"><div className="praxis-mark">P</div><span className="praxis-name">ACADEMIA PRAXIS</span><small>Competências Aplicadas para Negócios</small><i/><span className="certificate-label">CERTIFICADO DE COMPETÊNCIA PRÁTICA</span><h2>{cert.name}</h2><p>concluiu os marcos verificáveis da trilha e demonstrou competência aplicada em</p><h3>{cert.title}</h3><p>por estruturar briefing e conteúdo, personalizar a experiência, validar a responsividade e concluir a publicação de um projeto funcional.</p><div className="certificate-signatures"><span><strong>{new Date(cert.issuedAt).toLocaleDateString('pt-BR')}</strong><small>Data de emissão</small></span><span><strong>Academia Praxis</strong><small>Unidade formativa</small></span></div><code>Credencial {cert.code} · Projeto: {cert.projectName}</code></div></div><div className="certificate-disclaimer"><ShieldCheck/><span>Programa formativo integrado ao Seu Funcionário. Esta credencial comprova a conclusão de atividades práticas dentro da plataforma; não é diploma acadêmico nem habilitação regulamentada.</span></div><div className="modal-actions"><Button variant="ghost" icon={Printer} onClick={print}>Imprimir ou salvar em PDF</Button><Button icon={Download} onClick={download}>Baixar certificado</Button></div></Modal>
}

function Certifications({db,update,business,setToast,go}){
  const relevant=db.sites.filter(x=>!business||x.businessId===business.id)
  const ranked=[...relevant].sort((a,b)=>websiteMilestones(b).filter(x=>x.done).length-websiteMilestones(a).filter(x=>x.done).length)
  const [siteId,setSiteId]=useState(ranked[0]?.id||'')
  const [view,setView]=useState(null)
  const site=relevant.find(x=>x.id===siteId)||ranked[0]
  const milestones=websiteMilestones(site),done=milestones.filter(x=>x.done).length,complete=done===milestones.length
  const issued=db.certificates.find(x=>x.track==='website-no-code'&&x.projectId===site?.id)
  const issue=()=>{if(!complete||issued)return;const cert={id:uid(),track:'website-no-code',projectId:site.id,projectName:site.name,name:db.user.name,title:'Competência Aplicada em Criação de Websites No-Code',issuedAt:new Date().toISOString(),code:`PRX-WEB-${new Date().getFullYear()}-${site.id.slice(0,8).toUpperCase()}`};update(d=>({...d,certificates:[cert,...(d.certificates||[])]}));setView(cert);setToast('Certificado emitido pela Academia Praxis')}
  const certs=db.certificates||[]
  return <PageTitle eyebrow="ACADEMIA PRAXIS" title="Competências que você consegue demonstrar" text="As credenciais são liberadas por evidências do trabalho realizado — não por tempo de uso ou cliques aleatórios."><div className="issuer-banner"><div className="praxis-mark">P</div><div><span className="eyebrow">UNIDADE FORMATIVA DO SEU FUNCIONÁRIO</span><h2>Academia Praxis</h2><p>Competências Aplicadas para Negócios</p></div><BadgeCheck/></div><section className="cert-track"><div className="track-head"><span className="track-icon"><Globe2/></span><div><span className="tag">TRILHA PRÁTICA</span><h2>Criação de Websites No-Code</h2><p>Da definição do objetivo à publicação de uma página funcional.</p></div><div className="track-score"><strong>{done}/{milestones.length}</strong><small>marcos</small></div></div>{relevant.length>1&&<Field label="Projeto avaliado"><select value={site?.id||''} onChange={e=>setSiteId(e.target.value)}>{relevant.map(x=><option value={x.id} key={x.id}>{x.name}</option>)}</select></Field>}<div className="milestone-list">{milestones.map((m,i)=><div className={m.done?'done':''} key={m.id}><span>{m.done?<CheckCircle2/>:<LockKeyhole/>}</span><div><small>Marco {i+1}</small><strong>{m.title}</strong><p>{m.text}</p></div></div>)}</div><div className="track-footer"><div><div className="meter"><span style={{width:`${done/milestones.length*100}%`}}/></div><small>{complete?'Todos os critérios foram comprovados.':`Faltam ${milestones.length-done} marcos para liberar a credencial.`}</small></div>{!site?<Button icon={Globe2} onClick={()=>go('sites')}>Criar primeiro site</Button>:issued?<Button icon={Award} onClick={()=>setView(issued)}>Ver certificado</Button>:<Button icon={GraduationCap} disabled={!complete} onClick={issue}>Emitir certificado</Button>}</div></section>{certs.length>0&&<section className="section"><div className="section-head"><div><span className="eyebrow">CREDENCIAIS EMITIDAS</span><h2>Meus certificados</h2></div></div><div className="credential-grid">{certs.map(c=><button key={c.id} onClick={()=>setView(c)}><span><Award/></span><div><strong>{c.title}</strong><small>{new Date(c.issuedAt).toLocaleDateString('pt-BR')} · {c.code}</small></div><ChevronRight/></button>)}</div></section>}{view&&<CertificateView cert={view} onClose={()=>setView(null)}/>}</PageTitle>
}

function Businesses({db,update,setToast}){
  const [modal,setModal]=useState(false),[editing,setEditing]=useState(null)
  const save=b=>{update(d=>{const exists=d.businesses.some(x=>x.id===b.id);return {...d,businesses:exists?d.businesses.map(x=>x.id===b.id?b:x):[b,...d.businesses],selectedBusinessId:b.id}});setModal(false);setToast('Perfil do negócio salvo')}
  return <PageTitle eyebrow="PERFIS DE NEGÓCIO" title="Seus negócios" text="Mantenha cada contexto separado e alterne quando precisar." action={<Button icon={Plus} onClick={()=>{setEditing(null);setModal(true)}}>Novo negócio</Button>}><div className="business-grid">{db.businesses.map(b=><article className={db.selectedBusinessId===b.id?'selected':''} key={b.id}><div><span className="business-avatar">{b.name[0]}</span>{db.selectedBusinessId===b.id&&<span className="selected-badge"><Check/>Selecionado</span>}</div><h3>{b.name}</h3><p>{b.segment||'Segmento não informado'}</p><small>{b.stage}</small><footer><Button variant="ghost" onClick={()=>update({...db,selectedBusinessId:b.id})}>Usar este</Button><button className="icon-button" onClick={()=>{setEditing(b);setModal(true)}}><Edit3/></button><button className="icon-button danger" onClick={()=>{if(confirm(`Excluir ${b.name}? Os itens vinculados não serão apagados.`))update(d=>({...d,businesses:d.businesses.filter(x=>x.id!==b.id),selectedBusinessId:d.selectedBusinessId===b.id?(d.businesses.find(x=>x.id!==b.id)?.id||null):d.selectedBusinessId}))}}><Trash2/></button></footer></article>)}</div>{db.businesses.length===0&&<Empty icon={Building2} title="Nenhum negócio cadastrado" text="Crie um perfil para personalizar ferramentas e organizar os dados." action="Criar negócio" onAction={()=>setModal(true)}/>} {modal&&<Modal wide title={editing?'Editar negócio':'Criar negócio'} onClose={()=>setModal(false)}><BusinessForm value={editing} onSave={save} onClose={()=>setModal(false)}/></Modal>}</PageTitle>
}

function PublicSite({site}){if(!site||!site.published)return <main className="public-missing"><Logo/><CircleAlert/><h1>Esta página não está disponível</h1><p>O endereço pode estar incorreto ou o site foi despublicado.</p></main>;return <iframe className="public-frame" sandbox="allow-forms allow-popups allow-top-navigation-by-user-activation" title={site.name} srcDoc={site.html}/>} 

export default function App(){
  const [db,update]=useDatabase(),[page,setPage]=useState('inicio'),[collapsed,setCollapsed]=useState(false),[mobile,setMobile]=useState(false),[toast,setToast]=useState(''),[businessMenu,setBusinessMenu]=useState(false)
  useEffect(()=>{document.documentElement.dataset.theme=db.preferences.theme},[db.preferences.theme])
  useEffect(()=>{if(toast){const t=setTimeout(()=>setToast(''),2400);return()=>clearTimeout(t)}},[toast])
  const publicSlug=location.pathname.match(/^\/s\/([^/]+)/)?.[1]
  if(publicSlug)return <PublicSite site={db.sites.find(x=>x.slug===publicSlug)}/>
  if(!db.user)return <Login update={update}/>
  if(!db.onboarding)return <Onboarding db={db} update={update}/>
  const business=db.businesses.find(x=>x.id===db.selectedBusinessId)||db.businesses[0]||null
  const go=p=>{setPage(p);setMobile(false)}
  const content=()=>{switch(page){case'inicio':return <Dashboard db={db} update={update} business={business} go={go} setToast={setToast}/>;case'comecar':return <Journeys db={db} update={update}/>;case'estrategia':case'marketing':return <Specialists db={db} update={update} business={business} setToast={setToast}/>;case'vendas':return <CRM db={db} update={update} business={business} setToast={setToast}/>;case'financeiro':return <Finance db={db} update={update} business={business} setToast={setToast}/>;case'operacao':return <Tasks db={db} update={update} business={business} setToast={setToast}/>;case'sites':return <Sites db={db} update={update} business={business} setToast={setToast}/>;case'documentos':return <Documents db={db} update={update} business={business} setToast={setToast}/>;case'ferramentas':return <ToolsHub setToast={setToast}/>;case'estudio':return <CreativeStudio db={db} update={update} business={business} setToast={setToast}/>;case'historico':return <HistoryPage db={db} update={update} business={business} setToast={setToast}/>;case'certificacoes':return <Certifications db={db} update={update} business={business} setToast={setToast} go={go}/>;case'businesses':return <Businesses db={db} update={update} setToast={setToast}/>;default:return null}}
  return <div className={`app ${collapsed?'collapsed':''}`}><aside className={mobile?'open':''}><div className="side-top"><Logo compact={collapsed}/><button className="icon-button desktop-collapse" onClick={()=>setCollapsed(!collapsed)}>{collapsed?<ChevronRight/>:<ChevronLeft/>}</button><button className="icon-button mobile-close" onClick={()=>setMobile(false)}><X/></button></div><nav>{nav.map(([id,label,I])=><button key={id} className={page===id?'active':''} onClick={()=>go(id)} title={collapsed?label:undefined}><I/><span>{label}</span></button>)}</nav><div className="side-bottom"><button onClick={()=>update(d=>({...d,preferences:{...d.preferences,theme:d.preferences.theme==='light'?'dark':'light'}}))}>{db.preferences.theme==='light'?<Moon/>:<Sun/>}<span>{db.preferences.theme==='light'?'Modo escuro':'Modo claro'}</span></button><button onClick={()=>{if(confirm('Encerrar esta sessão? Seus projetos continuarão salvos neste dispositivo.')){endSession();update(d=>({...d,user:null}))}}}><LogOut/><span>Sair</span></button></div></aside>{mobile&&<div className="mobile-overlay" onClick={()=>setMobile(false)}/>}<main className="workspace"><header className="topbar"><button className="icon-button mobile-menu" onClick={()=>setMobile(true)}><Menu/></button><div className="top-business"><span>Negócio ativo</span><button onClick={()=>setBusinessMenu(!businessMenu)}><span className="business-avatar small">{business?.name?.[0]||'+'}</span><strong>{business?.name||'Criar negócio'}</strong><ChevronRight className={businessMenu?'rotated':''}/></button>{businessMenu&&<div className="business-popover">{db.businesses.map(b=><button key={b.id} onClick={()=>{update(d=>({...d,selectedBusinessId:b.id}));setBusinessMenu(false)}}><span className="business-avatar small">{b.name[0]}</span><span><strong>{b.name}</strong><small>{b.segment||'Sem segmento'}</small></span>{business?.id===b.id&&<Check/>}</button>)}<button className="manage" onClick={()=>{go('businesses');setBusinessMenu(false)}}><Building2/>Gerenciar negócios</button></div>}</div><div className="top-actions"><button className="icon-button" onClick={()=>update(d=>({...d,preferences:{...d.preferences,theme:d.preferences.theme==='light'?'dark':'light'}}))}>{db.preferences.theme==='light'?<Moon/>:<Sun/>}</button><button className="user-chip" onClick={()=>go('businesses')}><span>{db.user.name[0]}</span><div><strong>{db.user.name}</strong><small>{db.user.email}</small></div></button></div></header><div className="page">{content()}</div></main><Toast toast={toast}/></div>
}
